  ('heelevel3-5ff21eeb-moex-00044', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關營利事業交際費之敘述何者正確？①公營事業之交際費用由主管機關分別核定，列入預', '["營利事業經營外銷業務，取得外匯收入者得在不超過當年度外銷結匯收入總額1%範圍內， 列支特別交際應酬費", "簽證申報交際費限額大於藍色申報", "交際費之進項稅額不可扣抵銷 項稅額", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00045', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '張先生具有美國及中華民國國籍，且在中華民國境內設有戶籍，其 113 年在臺灣居留期間為 60 天，有中華民國來源所得60萬元及大陸地區所得30萬元，其113年所得如何申報？', '["中華民國來源所得辦理綜合所得稅結算申報，大陸地區所得申報所得基本稅額", "中華民國來源所得及大陸地區所得一起辦理綜合所得稅結算申報", "中華民國來源所得辦理綜合所得稅結算申報，大陸地區所得免課", "中華民國來源所得就源扣繳免辦理綜合所得稅結算申報，大陸地區所得免課"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00046', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '納稅義務人潘先生扶養二名子女；分別為107年4月5日出生及110年2月1日出生，請問潘先 生於114年5月申報綜合所得稅時，可扣除之幼兒學前特別扣除額為若干？', '["37.5萬元", "24萬元", "15萬元", "12萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00047', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列貨物或勞務何者之營業稅稅率為零？', '["醫院、診所、療養院提供之醫療勞務", "在國外提供而在國內使用之勞務", "國際運輸用之船舶", "依法設立之免稅商店銷售與入境旅客之貨物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00048', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關營利事業房地合一稅之規定何者錯誤？', '["依土地稅法規定繳納之土地增值稅，不得列為成本費用", "土地漲價總數額依公告土地現值計算", "獨資、合夥組織營利事業交易房屋、土地，應由獨資資本主或合夥組織合夥人就該房屋、土地 交易所得額適用個人房地合一稅規定，不計入獨資、合夥組織營利事業之所得額", "營利事業交易其興建房屋完成後第一次移轉之房屋及其坐落基地，應計入營利事業所得額課稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00049', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列何者屬於進口？①貨物自國外進入科學園區  ②貨物自國外進入農業科技園區  ③貨物自', '["貨物自自由貿易港區進入軟體工業園區", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00050', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲車商於今年3、4月向非加值型營業人以210,000元及84,000元購入A、B二輛舊乘人小汽車， 5月時出售A車，售價315,000元（含稅），若甲車商並無其他交易，則甲車商5~6月營業稅之應 納稅額為何？', '["0", "1,000元", "5,000元", "15,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00051', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關地價稅之敘述，下列何者錯誤？', '["採累進稅率，最高稅率為55‰", "按每一土地所有權人在每一直轄市或縣（市）轄區內之地價總額計徵", "累進起點地價，以各該直轄市或縣（市）土地7公畝之平均地價為準", "累進起點地價之計算，不包括自用住宅用地、工廠用地、礦業用地、農業用地及免稅土地在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00052', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '李小姐於114年1月25日向王先生購買房屋供自用住宅用，並於該日完成產權登記，則該期房 屋稅納稅義務人為何？', '["李小姐", "王先生", "113年7月~114年1月為王先生；114年2月~6月為李小姐", "114年1月為王先生；114年2月~12月為李小姐"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00053', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關土地增值稅之敘述何者錯誤？', '["依漲價倍數累進課稅", "可用公告現值來計算應納土地增值稅", "贈與自用住宅用地之土地增值稅稅率為10%", "土地有償移轉，土地增值稅之納稅義務人為原所有權人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
